#include <stdio.h>
#include <stdlib.h>		
#define LAST 1000000000000000001L
main()
{
	long long int year, yarr[4000];
	long long twop[66];
	long long p,pmax,a,b;
	int i,j,ind,count;
	p = 1;
	twop[0]=1;
	for (i=1; p<LAST; i++)
	{
		p = p*2;
		twop[i] = p;
	}
	pmax=i;
	ind=0;
	for (i=2; i< pmax; i++)
		for (j=i-1; j>0; j--)
			yarr[ind++] = twop[i]-1-twop[j-1];
	scanf("%lld %lld", &a, &b);
	count=0;
	for (i=0; i<ind; i++)
		if (a<= yarr[i] && b >= yarr[i]) count++;
	printf("%d\n",count);
	return 0;	
}

