use std::io::{self, Stdin};
use std::str::{self, FromStr};
use std::error::Error;

fn exec() {
    let mut sc = Scanner::new();
    let a: u64 = sc.ne();
    let b: u64 = sc.ne();
    let mut cnt = 0;
    for i in 0..64 {
        let k = (1 << i) - 1;
        for j in 0..i - 1 {
            let aim = k ^ (1 << j);
            // println!("{:b}", aim);
            if a <= aim && aim <= b {
                cnt += 1;
            }
        }
    }
    println!("{}", cnt);
}

fn main() {
    const STACK: usize = 16 * 1024 * 1024;
    let _ = std::thread::Builder::new()
        .stack_size(STACK)
        .spawn(|| { exec(); })
        .unwrap()
        .join()
        .unwrap();
}

